sql.trim:
and a.store_id = #{store_id}
and a.recycle = 0
and c.recycle = 0
and a.mch_status = 2
and a.product_number = #{product_number}
and m.id =#{mch_id}
and a.lang_code =#{lang_code}
and m.name =#{mch_name}

    
        and a.status != 5
        and a.status = 5
    


    
        #{status,jdbcType=INTEGER}
    

and a.gongyingshang = #{supplierId} and a.mch_id = 0
and a.gongyingshang = ''
and m.name like concat('%',#{mch_name_like},'%')
and a.product_title like CONCAT('%',#{product_title_like},'%')
AND b.add_date   >=   #{startDate}
AND b.add_date   <=   #{endDate}

mapper.select:
select c.id,a.product_number,a.product_title,a.imgurl,a.`status`,a.mch_id,a.upper_shelf_time,c.id,c.pid,c.price,c.yprice,c.attribute,c.total_num,c.num,b.add_date,m.name as shop_name from lkt_configure as c left join lkt_product_list as a on c.pid = a.id left join lkt_mch as m on a.mch_id = m.id left join (select max(add_date) as add_date, attribute_id from lkt_stock group by attribute_id) as b on c.id = b.attribute_id
order by a.upper_shelf_time desc
LIMIT #{pageStart},#{pageEnd}

mapper.sql:
and a.store_id = #{store_id}
and a.store_id=b.store_id
and a.recycle = 0
and a.mch_status = 2

 AND c.num   <=   a.min_inventory


    and a.is_presell = 0


    
        #{stockType,jdbcType=INTEGER}
    

and b.mch_id = #{mch_id}
and b.type = #{stockType}
and b.product_id = #{product_id}
and b.attribute_id = #{attribute_id}
and a.product_title like CONCAT('%',#{product_title_like},'%')
and m.name like concat('%',#{mch_name},'%')
AND b.add_date   >=   #{startDate}
AND b.add_date   <=   #{endDate}
AND b.add_date   >=   #{stockStartDate}
AND b.add_date   <=   #{stockEndDate}

    
        and a.status != 5
        and a.status = 5
    

and a.gongyingshang = #{supplierId} and a.mch_id = 0
and a.gongyingshang = ''
and a.status != 4
and a.lang_code = #{lang_code}
and a.status != 5

mapper.select:
SELECT a.goodsId, a.attrId, a.product_number, a.product_title, a.imgurl, a.upper_shelf_time, a.status, a.mch_id, a.price, a.yprice, a.attribute, a.total_num, a.num, a.flowing_num, a.user_id, a.type, a. add_date, a.content, a.byMchId, a.is_acceptance, a.name, a.min_inventory FROM ( SELECT b.product_id goodsId, b.attribute_id attrId, a.product_number, a.product_title, a.imgurl, a.upper_shelf_time AS upper_shelf_time, a.status, a.mch_id, c.price, c.yprice, c.attribute, c.total_num, c.num AS num, b.flowing_num, b.user_id, b.type, b.add_date AS add_date, b.content, b.mch_id byMchId, b.is_acceptance, m.name, a.min_inventory, ROW_NUMBER() over(partition by b.product_id) AS top, ROW_NUMBER() over(partition by c.id) AS top2 FROM lkt_stock AS b RIGHT JOIN lkt_product_list AS a ON b.product_id = a.id RIGHT JOIN lkt_configure AS c ON b.attribute_id = c.id LEFT JOIN lkt_mch AS m ON a.mch_id = m.id
AND b.flowing_num != 0
) AS a
and a.top <2 and a.top2 <2
order by add_date desc LIMIT #{pageStart},#{pageEnd}

        select ifnull(sum(flowing_num), 0) num
        from lkt_stock
        
            
                and store_id=#{storeid}
            

            
                and type=#{type}
            
            
                and add_date  >= #{date}

select ifnull(count(1), 0) num
from lkt_stock

    
        and store_id=#{storeid}
    
    
        and add_date  >=#{date}
    
    and type=2
